            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            className="h-12 w-12 rounded-lg mr-2 text-primary"
          >
            <path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z" />
            <path d="M7.5 12h9M12 7.5v9" />
